import "math"

func min(a, b int64) int64 {
    if a < b {
        return a
    }
    return b
}

func max(a, b int64) int64 {
    if a > b {
        return a
    }
    return b
}

func solve(nums []int64) int64 {
    n := len(nums)
    if n < 4 {
        return math.MinInt64
    }

    prefix := make([]int64, n+1)
    for i := 0; i < n; i++ {
        prefix[i+1] = prefix[i] + nums[i]
    }

    dec_run := make([]int, n)
    inc_run := make([]int, n)
    dec_run[0] = 1
    inc_run[0] = 1
    for i := 1; i < n; i++ {
        if nums[i-1] > nums[i] {
            dec_run[i] = dec_run[i-1] + 1
        } else {
            dec_run[i] = 1
        }
        if nums[i-1] < nums[i] {
            inc_run[i] = inc_run[i-1] + 1
        } else {
            inc_run[i] = 1
        }
    }

    right_max_inc := make([]int64, n)
    right_max_inc[n-1] = prefix[n]
    for i := n-2; i >= 0; i-- {
        if nums[i] < nums[i+1] {
            right_max_inc[i] = max(prefix[i+1], right_max_inc[i+1])
        } else {
            right_max_inc[i] = prefix[i+1]
        }
    }

    size := n+1
    logTable := make([]int, size+1)
    logTable[0] = 0
    if size >= 1 {
        logTable[1] = 0
    }
    for i := 2; i <= size; i++ {
        logTable[i] = logTable[i>>1] + 1
    }
    k := logTable[size]
    st := make([][]int64, k+1)
    st[0] = make([]int64, size)
    copy(st[0], prefix)

    for j := 1; j <= k; j++ {
        segmentSize := size - (1 << j) + 1
        st[j] = make([]int64, segmentSize)
        for i := 0; i < segmentSize; i++ {
            st[j][i] = min(st[j-1][i], st[j-1][i+(1<<(j-1))])
        }
    }

    query := func(l, r int) int64 {
        length := r - l + 1
        j := logTable[length]
        return min(st[j][l], st[j][r - (1<<j) + 1])
    }

    best := int64(math.MinInt64)
    for q := 1; q <= n-2; q++ {
        if dec_run[q] < 2 {
            continue
        }
        p := q - dec_run[q] + 1
        if p <= 0 || inc_run[p] < 2 {
            continue
        }
        if nums[q] >= nums[q+1] {
            continue
        }
        l_start := p - inc_run[p] + 1
        min_prefix := query(l_start, p-1)
        candidate := right_max_inc[q] - min_prefix
        if candidate > best {
            best = candidate
        }
    }

    return best
}
