            if state0[i-1] != MIN {
                state1[i] = state0[i-1] + nums[i]
            }
            if state1[i-1] != MIN {
                candidate := state1[i-1] + nums[i]
                if candidate > state1[i] {
                    state1[i] = candidate
                }
            }
        }
    }

    for i := 1; i < n; i++ {
        if nums[i] > nums[i-1] {
            if state1[i-1] != MIN {
                state2[i] = state1[i-1] + nums[i]
            }
            if state2[i-1] != MIN {
                candidate := state2[i-1] + nums[i]
                if candidate > state2[i] {
