package main

func solve(nums []int64) int64 {
    const inf int64 = 1000000000000000000
    n := len(nums)
    if n < 4 {
        return 0
    }

    min64 := func(a, b int64) int64 {
        if a < b {
            return a
        }
        return b
    }
    max64 := func(a, b int64) int64 {
        if a > b {
            return a
        }
        return b
    }

    P := make([]int64, n+1)
    for i := 0; i < n; i++ {
        P[i+1] = P[i] + nums[i]
    }

    left_inc := make([]int, n)
    left_inc[0] = 1
    for i := 1; i < n; i++ {
        if nums[i] > nums[i-1] {
            left_inc[i] = left_inc[i-1] + 1
        } else {
            left_inc[i] = 1
        }
    }

    dec := make([]int, n)
    dec[n-1] = 1
    for i := n-2; i>=0; i-- {
        if nums[i] > nums[i+1] {
            dec[i] = dec[i+1] + 1
        } else {
            dec[i] = 1
        }
    }

    inc_right := make([]int, n)
    inc_right[n-1] = 1
    for i := n-2; i>=0; i-- {
        if nums[i] < nums[i+1] {
            inc_right[i] = inc_right[i+1] + 1
        } else {
            inc_right[i] = 1
        }
    }

    logForArray := func(size int) int {
        logN := 0
        for (1 << logN) < size {
            logN++
        }
        return logN
    }

    buildSparseTable := func(a []int64, f func(int64, int64) int64) [][]int64 {
        n := len(a)
        logN := logForArray(n)
        if logN == 0 {
            return [][]int64{a}
        }
        st := make([][]int64, logN)
        st[0] = make([]int64, n)
        copy(st[0], a)
        for j := 1; j < logN; j++ {
            st[j] = make([]int64, n)
            step := 1 << (j-1)
            for i := 0; i < n; i++ {
                if i + step >= n {
                    break
                }
                st[j][i] = f(st[j-1][i], st[j-1][i+step])
            }
        }
        return st
    }

    querySparseTable := func(st [][]int64, l, r int, f func(int64, int64)int64, defaultVal int64) int64 {
        if l > r {
            return defaultVal
        }
        length := r - l + 1
        k := 0
        for (1 << (k+1)) <= length {
            k++
        }
        if k >= len(st) {
            k = len(st)-1
        }
        step := 1 << k
        res1 := st[k][l]
        res2 := st[k][r - step + 1]
        return f(res1, res2)
    }

    st_min_P := buildSparseTable(P, min64)
    st_max_P := buildSparseTable(P, max64)

    M := make([]int64, n)
    for q := 0; q < n; q++ {
        if inc_right[q] < 2 {
            M[q] = -inf
        } else {
            L_ind := q + 2
            R_ind := q + inc_right[q]
            if R_ind > n {
                R_ind = n
            }
            if L_ind <= R_ind {
                M[q] = querySparseTable(st_max_P, L_ind, R_ind, max64, -inf)
            } else {
                M[q] = -inf
            }
        }
    }

    st_max_M := buildSparseTable(M, max64)

    ans := -inf
    for p := 1; p < n-1; p++ {
        if left_inc[p] < 2 || dec[p] < 2 {
            continue
        }
        L_start := p - left_inc[p] + 1
        if L_start < 0 {
            continue
        }
        minL := querySparseTable(st_min_P, L_start, p-1, min64, inf)
        q_low := p + 1
        q_high := p + dec[p] - 1
        if q_high >= n {
            q_high = n - 1
        }
        if q_low > q_high {
            continue
        }
        maxM := querySparseTable(st_max_M, q_low, q_high, max64, -inf)
        candidate := maxM - minL
        if candidate > ans {
            ans = candidate
        }
    }
    return ans
}
